import autogen
from autogen import ConversableAgent, Agent
from typing import Optional, List, Dict, Union
from vex_sdk import VexClient, GuardrailPolicy, VexViolation

def make_vex_reply_filter(vex: VexClient, policy: GuardrailPolicy, conversation_id: str):
    """
    Returns a reply function compatible with AutoGen's register_reply() API.
    This filter runs BEFORE the agent's normal reply logic.
    """
    def vex_guardrail_filter(
        recipient: ConversableAgent,
        messages: Optional[List[Dict]] = None,
        sender: Optional[Agent] = None,
        config: Optional[dict] = None
    ) -> tuple[bool, Optional[Union[str, Dict]]]:

        if not messages:
            return False, None  # No message to check, pass through

        last_message = messages[-1]
        content = last_message.get("content", "")

        # Skip empty messages or tool call results with no text
        if not content or not isinstance(content, str):
            return False, None

        try:
            result = vex.check_message(
                message=content,
                policy=policy,
                conversation_id=conversation_id,
                metadata={
                    "sender_name": sender.name if sender else "unknown",
                    "recipient_name": recipient.name,
                    "message_index": len(messages),
                    "framework": "autogen"
                }
            )

            if result.blocked:
                violation_summary = "; ".join(
                    f"{v.rule}: {v.reason}" for v in result.violations
                )
                # Return (True, reply) to short-circuit AutoGen's reply chain
                return True, (
                    f"[VEX GUARDRAIL] Message blocked. Violations: {violation_summary}. "
                    f"Conversation halted. Please review agent configuration."
                )

            if result.warnings:
                # Log warnings but allow message through
                for warning in result.warnings:
                    print(f"[VEX WARNING] {recipient.name}: {warning.rule} - {warning.reason}")

        except Exception as e:
            # Fail open: if Vex is unreachable, log and continue
            print(f"[VEX ERROR] Guardrail check failed: {e}. Allowing message through.")

        return False, None  # Pass through to normal reply logic

    return vex_guardrail_filter
